INSERT INTO public.play_questions (domain, category, content, options, correct_answer_index, explanation)
VALUES
  ('funbrain', 'analytical', '{"text": "If \"MENTAL\" is coded as \"LNDOMZUK\" (each letter replaced by the letter before it and the letter after it in the alphabet), how is \"TEST\" coded?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["RTSUFDUS", "SUDFRTST", "TSEFDURS", "SUDFRTSU"]'::jsonb, 3, 'T→SU, E→DF, S→RT, T→SU; concatenate → SUDFRTSU.'),
  ('funbrain', 'analytical', '{"text": "In a code, \"ROSE\" = 6821, \"CHAIR\" = 73456, \"PREACH\" = 961473. Code for \"SEARCH\"?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["734562", "961473", "214673", "214678"]'::jsonb, 2, 'Map letters: S=2,E=1,A=4,R=6,C=7,H=3 → SEARCH = 214673.'),
  ('funbrain', 'analytical', '{"text": "If \"WATER\" is written as \"YCVGT\" (each letter shifted +2), how is \"FIRE\" written?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["HJTG", "GJTG", "HKUG", "HKTG"]'::jsonb, 3, 'F+2=H, I+2=K, R+2=T, E+2=G.'),
  ('funbrain', 'analytical', '{"text": "\"256\" = you are good, \"637\" = we are bad, \"358\" = good and bad. Which digit is \"and\"?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["3", "5", "8", "6"]'::jsonb, 2, '6=are, 5=good, 3=bad; in 358 the remaining digit 8 is and.'),
  ('funbrain', 'analytical', '{"text": "If A = 1, B = 2, … and PAT = 16+1+20 = 37, what is PART?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["54", "56", "52", "55"]'::jsonb, 3, 'P(16)+A(1)+R(18)+T(20)=55.'),
  ('funbrain', 'analytical', '{"text": "If \"DELHI\" = 73541 and \"CALCUTTA\" = 82589662, code for \"CALICUT\"?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["8258966", "82589662", "8251891", "8251896"]'::jsonb, 3, 'Same letter→digit map: C=8,A=2,L=5,I=1,U=9,T=6.'),
  ('funbrain', 'analytical', '{"text": "If \"GLARE\" = 67810 and \"MONSOON\" = 2395339, code for \"RANSOM\"?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["198532", "189523", "189532", "189352"]'::jsonb, 2, 'R=1,A=8,N=9,S=5,O=3,M=2.'),
  ('funbrain', 'analytical', '{"text": "Code: A=2, B=4, C=6, … (each letter’s position × 2). Sum for \"OWL\"?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["96", "98", "100", "104"]'::jsonb, 2, 'O(15×2)+W(23×2)+L(12×2)=30+46+24=100.'),
  ('funbrain', 'analytical', '{"text": "If \"MIND\" → \"KGLB\" and \"ARGUE\" → \"YPESC\" (each letter −2), what is \"DIAGRAM\"?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["BGYESYK", "CEZFTRZ", "BGYESYJ", "BGYFTYK"]'::jsonb, 0, 'Each letter shifted back by 2 in the alphabet.'),
  ('funbrain', 'analytical', '{"text": "If \"RED\" = 6720 (add 2 to each letter’s position, then write digits in reverse letter order N←…←R), what is \"GREEN\"?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["9071721", "1677029", "1677209", "1677207"]'::jsonb, 2, 'Reverse order N,E,E,R,G with values 16,7,7,20,9 → 1677209.'),
  ('funbrain', 'analytical', '{"text": "Pointing to a photo, a man said: \"I have no brother or sister, but that man’s father is my father’s son.\" Whose photo?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["His father’s", "His nephew’s", "His own", "His son’s"]'::jsonb, 3, 'Father’s son with no siblings = himself; the man’s father is the speaker → the man in the photo is his son.'),
  ('funbrain', 'analytical', '{"text": "A is B’s sister. C is B’s mother. D is C’s father. E is D’s mother. How is A related to D?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Sister", "Niece", "Daughter", "Granddaughter"]'::jsonb, 3, 'D is C’s father and C is A’s mother → D is A’s grandfather (maternal line).'),
  ('funbrain', 'analytical', '{"text": "A girl says of a boy: \"He is the son of the daughter of the father of my uncle.\" How is the boy related to the girl?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Father", "Uncle", "Brother or cousin", "Nephew"]'::jsonb, 2, 'Grandfather’s daughter may be her mother (brother) or an aunt (cousin).'),
  ('funbrain', 'analytical', '{"text": "A woman introduces a man as the son of the brother of her mother. How is he related to her?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Uncle", "Nephew", "Brother", "Cousin"]'::jsonb, 3, 'Mother’s brother’s son = first cousin.'),
  ('funbrain', 'analytical', '{"text": "A+B = A is brother of B; A−B = sister; A×B = A is father of B. Which shows C is son of M?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["M × C + F", "M + C × F", "C × M + F", "M × F + C"]'::jsonb, 0, 'M×C: M father of C; C+F: C brother of F → C is male child of M.'),
  ('funbrain', 'analytical', '{"text": "Deepak: \"His only brother is the father of my daughter’s father.\" How is the gentleman related to Deepak?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Grandfather", "Uncle", "Brother", "Father"]'::jsonb, 1, 'Daughter’s father = Deepak; that man’s brother = Deepak’s father → the man is Deepak’s uncle.'),
  ('funbrain', 'analytical', '{"text": "Q’s mother is sister of P and daughter of M. S is daughter of P and sister of T. How is M related to T?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Mother", "Cannot tell", "Aunt", "Grandmother or grandfather"]'::jsonb, 3, 'P is child of M; T is child of P → M is T’s grandparent (gender of M unknown).'),
  ('funbrain', 'analytical', '{"text": "Family A,B,C,D,E,F: B is son of C but C is not B’s mother. A and C are married. E is C’s brother. D is A’s daughter. F is A’s brother. Who is B’s mother?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["C", "E", "A", "D"]'::jsonb, 2, 'C is father; married couple A,C → A is mother.'),
  ('funbrain', 'analytical', '{"text": "A girl points to a lady: \"She is the daughter-in-law of the grandmother of my father’s only son.\" Relation of lady to girl?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Cousin", "Grandmother", "Sister", "Mother or aunt"]'::jsonb, 3, 'Father’s only son may be her brother; grandmother’s daughter-in-law can be mother or aunt.'),
  ('funbrain', 'analytical', '{"text": "X to Y: \"I am the mother of your father’s brother’s son.\" How is X related to Y?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Aunt", "Mother", "Sister", "Grandmother"]'::jsonb, 0, 'Father’s brother’s son = cousin; cousin’s mother = aunt to Y.'),
  ('funbrain', 'analytical', '{"text": "Walk 5 km south, turn right 3 km, turn left 5 km. Direction from start?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["South-West", "North-West", "Due south", "South-East"]'::jsonb, 0, 'Net south and west of origin.'),
  ('funbrain', 'analytical', '{"text": "North 20 m, right 30 m, right 35 m, left 15 m, left 15 m. Displacement from start?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["45 m East", "45 m West", "0 m", "15 m East"]'::jsonb, 0, 'Vertical legs cancel; horizontal 30+15=45 m east.'),
  ('funbrain', 'analytical', '{"text": "Morning after sunrise, Vimal walks and meets Stephen from opposite direction. Stephen’s shadow falls to Vimal’s right. Vimal faces?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["North", "West", "East", "South"]'::jsonb, 3, 'Morning sun east → shadows west; Vimal’s right is west → Vimal faces south.'),
  ('funbrain', 'analytical', '{"text": "Clock placed so at 12 noon minute hand points north-east. At 1:30 PM, hour hand points?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["South-East", "North", "East", "North-East"]'::jsonb, 2, 'Clock rotated 45° clockwise; hour direction at 1:30 maps to east.'),
  ('funbrain', 'analytical', '{"text": "A east of B; C south of A; D north of C. Direction of D from B?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["North-East", "Cannot be determined", "East", "South"]'::jsonb, 1, 'D north of C but horizontal offset from B is not fixed.'),
  ('funbrain', 'analytical', '{"text": "Facing NW, turn 90° clockwise, then 180° anticlockwise, then 90° anticlockwise. Now facing?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["North-West", "North-East", "South-East", "South-West"]'::jsonb, 2, 'Net −180° from NW → SE.'),
  ('funbrain', 'analytical', '{"text": "12 km north, turn right, walk 5 km. Shortest distance back to start?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["12 km", "7 km", "17 km", "13 km"]'::jsonb, 3, 'Right from north is east; √(12²+5²)=13 km.'),
  ('funbrain', 'analytical', '{"text": "X is 1 km NE of Y. Y is 1 km SE of Z. W is 1 km west of Z. P is 1 km south of W. Q is 1 km east of P. Distance X to Q?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["√5 km", "1 km", "3 km", "2 km"]'::jsonb, 2, 'Fix coordinates from the chain; straight-line distance works out to 3 km in the standard layout.'),
  ('funbrain', 'analytical', '{"text": "Rat: 20 m east, right 10 m, right 9 m, left 5 m, left 12 m, left 6 m. Final facing?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["West", "South", "North", "East"]'::jsonb, 2, 'Track heading after each turn from east.'),
  ('funbrain', 'analytical', '{"text": "Facing south: right 20 m, right 10 m, left 10 m. Direction from start?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["North-West", "North-East", "South-West", "Due west"]'::jsonb, 0, 'Path nets north and west of origin.'),
  ('funbrain', 'analytical', '{"text": "Statements: All bats are boys. All boys are gloves. Conclusions: I. All bats are gloves. II. All gloves are bats.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Both follow", "Only Conclusion I follows", "Neither follows", "Only II follows"]'::jsonb, 1, 'Bats ⊆ boys ⊆ gloves → I. II need not hold.'),
  ('funbrain', 'analytical', '{"text": "Statements: Some papers are pens. All pens are scales. I. Some papers are scales. II. Some scales are pens.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Both I and II follow", "Neither follows", "Only II follows", "Only I follows"]'::jsonb, 0, 'Papers meeting pens lie in scales; all pens are scales ⇒ some scales are pens.'),
  ('funbrain', 'analytical', '{"text": "Statements: No cat is a rat. All rats are dogs. I. No cat is a dog. II. Some dogs are not cats.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Only Conclusion II follows", "Only I follows", "Both follow", "Neither follows"]'::jsonb, 0, 'Rat-dogs are not cats; cats may still be other dogs → I fails.'),
  ('funbrain', 'analytical', '{"text": "Statements: All cars are wheels. Some wheels are heavy. I. Some cars are heavy. II. No car is heavy.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Only I follows", "Neither follows", "Either I or II follows", "Only II follows"]'::jsonb, 2, 'No definite link between cars and heavy; classical either-or.'),
  ('funbrain', 'analytical', '{"text": "Statements: Some cats are kittens. All dogs are kittens. I. Some cats are dogs. II. No dog is a cat.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Both follow", "Only I follows", "Either I or II follows", "Neither follows"]'::jsonb, 2, 'Cats and dogs subsets of kittens; mutual exclusion or overlap undetermined.'),
  ('funbrain', 'analytical', '{"text": "Statements: All windows are doors. No door is a wall. I. No window is a wall. II. No wall is a door.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Only I follows", "Only II follows", "Neither follows", "Both I and II follow"]'::jsonb, 3, 'Windows ⊆ doors disjoint from walls; II restates symmetry of disjointness.'),
  ('funbrain', 'analytical', '{"text": "Statements: Some apples are red. All red things are sweet. I. Some apples are sweet. II. All sweet things are red.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Both follow", "Only Conclusion I follows", "Only II follows", "Neither follows"]'::jsonb, 1, 'Red apples are sweet; sweet things need not all be red.'),
  ('funbrain', 'analytical', '{"text": "Statements: All birds can fly. Some flying objects are airplanes. I. Some birds are airplanes. II. No airplane is a bird.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Either I or II follows", "Only I follows", "Both follow", "Neither follows"]'::jsonb, 0, 'Birds and planes only linked through flying; no definite relation.'),
  ('funbrain', 'analytical', '{"text": "Statements: (Hypothetical) No square is a rectangle. All rectangles are circles. I. Some circles are not squares. II. No square is a circle.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Both follow", "Only Conclusion I follows", "Neither follows", "Only II follows"]'::jsonb, 1, 'Rectangle-circles are not squares; squares could still be non-rectangle circles.'),
  ('funbrain', 'analytical', '{"text": "Statements: Some books are magazines. Some magazines are novels. I. Some books are novels. II. No book is a novel.", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Neither follows", "Both follow", "Only I follows", "Either I or II follows"]'::jsonb, 3, 'Two ''some'' chains give no definite link between books and novels.'),
  ('funbrain', 'analytical', '{"text": "Next: 3, 7, 15, 31, 63, …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["255", "125", "127", "129"]'::jsonb, 2, '×2+1 each step: 63×2+1=127.'),
  ('funbrain', 'analytical', '{"text": "Missing: 1, 9, 25, 49, ?, 121", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["100", "64", "81", "91"]'::jsonb, 2, 'Odd squares: 1²,3²,5²,7²,9²,11² → 9²=81.'),
  ('funbrain', 'analytical', '{"text": "Next: Z, W, S, P, L, I, E, …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["D", "A", "C", "B"]'::jsonb, 3, 'Backward skips alternate 3,4 letters.'),
  ('funbrain', 'analytical', '{"text": "Odd one out: 8, 27, 64, 100, 125, 216", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["27", "100", "64", "125"]'::jsonb, 1, 'All are perfect cubes except 100 (square only).'),
  ('funbrain', 'analytical', '{"text": "Next: 2, 1, 1/2, 1/4, …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["1/16", "1/8", "1/6", "0"]'::jsonb, 1, 'Each term ÷2.'),
  ('funbrain', 'analytical', '{"text": "Next: B2CD, BCD4, B5CD, BC6D, …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["B2C8D", "BCD7", "BC7D", "B7CD"]'::jsonb, 1, 'Digit increases 2,4,5,6,7 cycling placement after B,C,D positions.'),
  ('funbrain', 'analytical', '{"text": "Wrong number: 4, 9, 19, 39, 79, 160, 319", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["39", "319", "79", "160"]'::jsonb, 3, 'Should be 79×2+1=159, not 160.'),
  ('funbrain', 'analytical', '{"text": "Next: 2, 3, 5, 7, 11, 13, 17, …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["23", "18", "19", "21"]'::jsonb, 2, 'Consecutive primes.'),
  ('funbrain', 'analytical', '{"text": "Fill: SCD, TEF, UGH, ____, WKL", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["WGH", "VIJ", "VJK", "VIK"]'::jsonb, 1, 'First letter advances; next two letters advance in pairs.'),
  ('funbrain', 'analytical', '{"text": "Next: 5, 11, 24, 51, 106, …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["212", "220", "213", "217"]'::jsonb, 3, '×2+1, ×2+2, … ×2+5: 106×2+5=217.'),
  ('funbrain', 'analytical', '{"text": "40 students in a row; Rohan 14th from left. Position from right?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["25th", "26th", "28th", "27th"]'::jsonb, 3, '40−14+1=27.'),
  ('funbrain', 'analytical', '{"text": "Sam 9th from top and 38th from bottom. Total students?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["47", "48", "45", "46"]'::jsonb, 3, '9+38−1=46.'),
  ('funbrain', 'analytical', '{"text": "60 students; girls = 2× boys. Kamal 17th from top; 9 girls ahead of Kamal. Boys after Kamal?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["12", "13", "11", "10"]'::jsonb, 0, '20 boys, 40 girls; Kamal is 8th boy → 20−8=12 boys after.'),
  ('funbrain', 'analytical', '{"text": "A taller than B, shorter than C. D taller than A, shorter than C. E tallest. Shortest?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["B", "D", "Cannot tell", "A"]'::jsonb, 0, 'Order E>C>D>A>B.'),
  ('funbrain', 'analytical', '{"text": "A 15th from left, B 4th from right, 3 boys between A and B. C just left of A. C’s position from right?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["7th", "9th", "10th", "8th"]'::jsonb, 1, 'Total 22; C is 14th from left → 22−14+1=9.'),
  ('funbrain', 'analytical', '{"text": "Boxes: P above Q; R below S; T between Q and R. Bottom box?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["S", "Q", "R", "T"]'::jsonb, 0, 'Top to bottom: P, Q, T, R, S.'),
  ('funbrain', 'analytical', '{"text": "A,B,C in queue: 5 between A and B, 8 between B and C; 3 ahead of C, 21 behind A. Minimum people in queue?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["28", "30", "25", "38"]'::jsonb, 0, 'Standard minimal-overlap arrangement yields 28.'),
  ('funbrain', 'analytical', '{"text": "5th of month is two days after Monday. Day before the 19th?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Wednesday", "Monday", "Thursday", "Tuesday"]'::jsonb, 3, '5th is Wednesday; 19th is Wednesday; day before is Tuesday.'),
  ('funbrain', 'analytical', '{"text": "Mohan 18th from either end. How many boys?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["34", "37", "36", "35"]'::jsonb, 3, '18+18−1=35.'),
  ('funbrain', 'analytical', '{"text": "50 in queue: Amrita 10th from front, Mukul 25th from behind, Maha midway between them. Maha from front?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["16th", "18th", "19th", "17th"]'::jsonb, 1, 'Mukul 26th from front; midpoint of 10 and 26 is 18.'),
  ('funbrain', 'analytical', '{"text": "Odd one out: Circle, Triangle, Square, Rectangle, Pentagon", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Rectangle", "Square", "Triangle", "Circle"]'::jsonb, 3, 'Only non-polygon (smooth curve).'),
  ('funbrain', 'analytical', '{"text": "Odd one out: Iron, Copper, Zinc, Aluminum, Brass", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Aluminum", "Copper", "Brass", "Zinc"]'::jsonb, 2, 'Alloy; others are elements.'),
  ('funbrain', 'analytical', '{"text": "Clock is to Time as Thermometer is to …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Heat energy", "Length", "Temperature", "Speed"]'::jsonb, 2, 'Instrument : quantity measured.'),
  ('funbrain', 'analytical', '{"text": "Ocean is to Water as Glacier is to …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Ice", "Snow", "Mountain", "Cold"]'::jsonb, 0, 'Large body : constituent material.'),
  ('funbrain', 'analytical', '{"text": "Odd pair: (Tree:Branch), (Hand:Finger), (Table:Chair), (Room:Floor)", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["(Room:Floor)", "(Table:Chair)", "(Tree:Branch)", "(Hand:Finger)"]'::jsonb, 1, 'Chair is not part of table; others are part-whole.'),
  ('funbrain', 'analytical', '{"text": "11 is to 121 as 15 is to …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["230", "200", "225", "256"]'::jsonb, 2, 'Square: 11²=121, 15²=225.'),
  ('funbrain', 'analytical', '{"text": "Odd one out: Tomato, Potato, Onion, Carrot, Radish", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Onion", "Potato", "Tomato", "Carrot"]'::jsonb, 2, 'Fruit/above ground; others often classed as root vegetables.'),
  ('funbrain', 'analytical', '{"text": "Prologue is to Book as Overture is to …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Chapter", "Symphony", "Novel", "Opera (or musical)"]'::jsonb, 3, 'Opening section of a performance medium.'),
  ('funbrain', 'analytical', '{"text": "Odd number: 13, 17, 23, 27, 29", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["27", "13", "23", "17"]'::jsonb, 0, '27=3×9 composite; others prime.'),
  ('funbrain', 'analytical', '{"text": "Eye is to Myopia as Teeth is to …", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Asthma", "Pyorrhea (or cavities)", "Arthritis", "Deafness"]'::jsonb, 1, 'Organ : common ailment of that organ.'),
  ('funbrain', 'analytical', '{"text": "Six people A–F sit in a circle facing center. D between F and B. A is second left of D and second right of E. Who faces A?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["D", "C", "E", "B"]'::jsonb, 3, 'Consistent circular order gives B opposite A.'),
  ('funbrain', 'analytical', '{"text": "Same setup. Who sits exactly between A and B?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["D", "E", "C", "F"]'::jsonb, 2, 'From the deduced clockwise order.'),
  ('funbrain', 'analytical', '{"text": "Same setup. Position of F with respect to E?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["Opposite", "Second to the left", "Immediate right", "Immediate left"]'::jsonb, 2, 'F adjacent to E on the appropriate side in the standard diagram.'),
  ('funbrain', 'analytical', '{"text": "Same setup. Who faces E?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["B", "D", "F", "A"]'::jsonb, 1, 'D sits opposite E in the arrangement.'),
  ('funbrain', 'analytical', '{"text": "P,Q,R,S,T in a line facing north. Q middle. P not at an end. T immediate right of R. S at extreme left. Order left→right?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["S, R, T, Q, P", "S, P, Q, R, T", "S, Q, P, R, T", "P, S, Q, R, T"]'::jsonb, 1, 'S left; Q center; RT block at right forces P second.'),
  ('funbrain', 'analytical', '{"text": "Same line. Who between P and R?", "pack": "cbse_analytical_puc100_medium"}'::jsonb, '["T", "Nobody", "S", "Q"]'::jsonb, 3, 'Q is center between P and R.'),
