-- CBSE PUC medium analytical (100), funbrain / analytical. Pack: cbse_analytical_puc100_medium.
-- Idempotent: delete this pack in analytical, then insert.

BEGIN;

DELETE FROM public.play_questions
WHERE domain = 'funbrain'
  AND category = 'analytical'
  AND (content->>'pack') = 'cbse_analytical_puc100_medium';


COMMIT;
